INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'listening', 'Family Pets', 'Listen to sentences about pets', '{"type":"listen_and_choose","instructions":"Listen and choose the correct pet.","exercises":[{"prompt":"I have a cat.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"A small furry pet that says meow"},{"prompt":"I see a dog in the park.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1,"hint":"A loyal friend that says woof"},{"prompt":"The rabbit is hopping.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":2,"hint":"It has long ears"},{"prompt":"The bird is singing.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3,"hint":"It has wings"},{"prompt":"My hamster is small.","options":["🐹 Hamster","🐘 Elephant","🦁 Lion","🦒 Giraffe"],"correct":0,"hint":"A tiny furry pet"},{"prompt":"I have a bird in a cage.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3,"hint":"It can chirp and often flies"},{"prompt":"The cat is sleeping on the sofa.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"A pet that loves to nap and purrs"},{"prompt":"I saw a rabbit munching on some carrots.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":2,"hint":"A pet that loves to hop and nibble"},{"prompt":"The dog is barking loudly.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1,"hint":"A friendly pet that protects your home"},{"prompt":"I can hear the bird singing.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3,"hint":"A pet often kept in a cage that can fly"},{"prompt":"The rabbit likes to play in the garden.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":2,"hint":"It enjoys hopping around in the grass"},{"prompt":"I have a dog who loves to fetch.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1,"hint":"A pet that enjoys playing with a ball"},{"prompt":"The cat caught a mouse.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"A skilled hunter that says meow"},{"prompt":"The bird is perched on a branch.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3,"hint":"It has feathers and can tweet"},{"prompt":"I saw a dog wagging its tail.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1,"hint":"A happy pet that loves to play"},{"prompt":"The rabbit is in its hutch.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":2,"hint":"A fluffy pet that loves carrots"},{"prompt":"I have a cat that likes to chase strings.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"A playful pet that enjoys climbing"},{"prompt":"The dog is guarding the house.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1,"hint":"Known as a loyal companion"},{"prompt":"The bird is flying high in the sky.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3,"hint":"A pet that can soar above the trees"},{"prompt":"My cat loves to play with yarn.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"A small, independent pet that purrs"}]}', 5),
('en', 'A1', 'listening', 'Transport', 'Identify transport modes', '{"type":"listen_and_choose","instructions":"Listen and pick the vehicle.","exercises":[{"prompt":"I ride a bus to school.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","✈️ Plane"],"correct":2,"hint":"A large vehicle for many people"},{"prompt":"I fly in a plane.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","✈️ Plane"],"correct":3,"hint":"It travels in the sky"},{"prompt":"My father drives a car.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","✈️ Plane"],"correct":0,"hint":"A vehicle for a small family"},{"prompt":"I have a blue bicycle.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","✈️ Plane"],"correct":1,"hint":"It has two wheels"},{"prompt":"The train is fast.","options":["🚂 Train","⛵ Boat","🚁 Helicopter","🚜 Tractor"],"correct":0,"hint":"It travels on tracks"},{"prompt":"I ride a bicycle in the park.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","🚂 Train"],"correct":1,"hint":"A two-wheeled vehicle you pedal"},{"prompt":"We take a train to the city.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","🚂 Train"],"correct":3,"hint":"It runs on tracks"},{"prompt":"I see a truck delivering goods.","options":["🚗 Car","🚚 Truck","🚌 Bus","✈️ Plane"],"correct":1,"hint":"A large vehicle for transporting items"},{"prompt":"My sister loves riding in a taxi.","options":["🚗 Car","🚖 Taxi","🚌 Bus","🚲 Bicycle"],"correct":1,"hint":"A car you can hire to go places"},{"prompt":"I travel by ferry to the island.","options":["🛳️ Ferry","🚗 Car","🚌 Bus","✈️ Plane"],"correct":0,"hint":"A boat that carries people across water"},{"prompt":"He has a motorcycle for quick rides.","options":["🚗 Car","🏍️ Motorcycle","🚌 Bus","🚲 Bicycle"],"correct":1,"hint":"A two-wheeled vehicle that goes fast"},{"prompt":"They drive a minivan for family trips.","options":["🚗 Car","🚐 Minivan","🚌 Bus","🚲 Bicycle"],"correct":1,"hint":"A larger vehicle for families"},{"prompt":"We board a cruise ship for vacation.","options":["🛳️ Ferry","🛥️ Yacht","🛳️ Cruise Ship","🚗 Car"],"correct":2,"hint":"A large ship for leisure travel"},{"prompt":"I often see people skateboarding.","options":["🚗 Car","🛹 Skateboard","🚌 Bus","🚲 Bicycle"],"correct":1,"hint":"A board with wheels you ride standing"},{"prompt":"We enjoy going on a road trip in our RV.","options":["🚗 Car","🏍️ Motorcycle","🚐 RV","🚌 Bus"],"correct":2,"hint":"A vehicle that can be used for living and traveling"},{"prompt":"I love watching hot air balloons.","options":["🚁 Helicopter","🎈 Hot Air Balloon","🚌 Bus","✈️ Plane"],"correct":1,"hint":"It floats in the air, filled with hot air"},{"prompt":"The school has a yellow school bus.","options":["🚗 Car","🚌 School Bus","🚲 Bicycle","🚐 Van"],"correct":1,"hint":"A vehicle specifically for students"},{"prompt":"My uncle drives a delivery van.","options":["🚗 Car","🚐 Delivery Van","🚌 Bus","🚲 Bicycle"],"correct":1,"hint":"A vehicle used for transporting packages"},{"prompt":"I want to ride in a luxury limousine.","options":["🚗 Car","🚖 Taxi","🚘 Limousine","🚌 Bus"],"correct":2,"hint":"A fancy, long car often for special occasions"},{"prompt":"We took a ride in a hovercraft.","options":["🚗 Car","🚤 Hovercraft","🚌 Bus","✈️ Plane"],"correct":1,"hint":"It travels over land and water on a cushion of air"}]}', 6),
('en', 'A1', 'listening', 'Weather Today', 'Listen to weather descriptions', '{"type":"listen_and_choose","instructions":"Choose the correct weather.","exercises":[{"prompt":"It is sunny today.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"The sun is shining"},{"prompt":"It is raining outside.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":1,"hint":"Water is falling from the sky"},{"prompt":"I see snow on the ground.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":2,"hint":"It is very cold and white"},{"prompt":"The wind is blowing.","options":["💨 Windy","☀️ Sunny","🌧️ Rainy","❄️ Snowy"],"correct":0,"hint":"Moving air"},{"prompt":"It is cloudy now.","options":["☁️ Cloudy","☀️ Sunny","🌙 Night","🌈 Rainbow"],"correct":0,"hint":"The sky is grey and full of clouds"},{"prompt":"The wind is howling and it''s very cloudy.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":3,"hint":"Thunder and lightning may come"},{"prompt":"The temperature is below freezing and there''s frost on the windows.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":2,"hint":"It''s very cold and icy"},{"prompt":"I can''t see the sun, but the air feels warm and humid.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":1,"hint":"It might rain soon"},{"prompt":"The sky is clear and bright blue.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"Perfect for a picnic"},{"prompt":"The forecast says there will be thunderstorms tonight.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":3,"hint":"Expect lightning and rain"},{"prompt":"I feel a chill in the air and see snowflakes falling.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":2,"hint":"Winter is here"},{"prompt":"There are puddles everywhere and the ground is wet.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":1,"hint":"It just rained"},{"prompt":"The forecast shows no clouds and high temperatures.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"Great beach weather"},{"prompt":"I hear thunder in the distance and it''s getting darker.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":3,"hint":"Storm is approaching"},{"prompt":"The ground is dry and the sun is shining brightly.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"A perfect sunny day"},{"prompt":"It''s drizzling outside and I need an umbrella.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":1,"hint":"Light rain is falling"},{"prompt":"The air is crisp and I see snowflakes on the ground.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":2,"hint":"Winter wonderland"},{"prompt":"The sun is setting, and the sky is painted with orange and pink.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"Beautiful evening"},{"prompt":"There are strong winds and heavy rain outside.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":3,"hint":"Take cover from the storm"},{"prompt":"It''s warm and sunny, perfect for a walk in the park.","options":["☀️ Sunny","🌧️ Rainy","❄️ Snowy","🌩️ Stormy"],"correct":0,"hint":"Ideal weather for outdoor activities"}]}', 7),
('en', 'A1', 'listening', 'Fruit and Vegetables', 'Identify healthy foods', '{"type":"listen_and_choose","instructions":"Pick the food mentioned.","exercises":[{"prompt":"I eat a red apple.","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A crunchy red fruit"},{"prompt":"The banana is yellow.","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":1,"hint":"A long yellow fruit"},{"prompt":"I like sweet grapes.","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":2,"hint":"Small purple or green fruit"},{"prompt":"I drink orange juice.","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":3,"hint":"A round orange fruit"},{"prompt":"I eat a green carrot.","options":["🥕 Carrot","🥦 Broccoli","🌽 Corn","🍅 Tomato"],"correct":0,"hint":"Wait, carrots are usually orange, but pick the carrot icon!"},{"prompt":"I love eating a juicy watermelon.","options":["🍉 Watermelon","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A large green fruit with red flesh"},{"prompt":"She prefers a crunchy carrot.","options":["🥕 Carrot","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"An orange vegetable often used in salads"},{"prompt":"He enjoys a slice of pizza.","options":["🍕 Pizza","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A popular Italian dish topped with cheese"},{"prompt":"They are having a bowl of cereal.","options":["🥣 Cereal","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"Often eaten for breakfast with milk"},{"prompt":"I drink fresh orange juice.","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":3,"hint":"A citrus fruit that is often juiced"},{"prompt":"She likes spicy chili peppers.","options":["🌶️ Chili Pepper","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A small, hot fruit used in cooking"},{"prompt":"They are eating a chocolate cake.","options":["🍰 Cake","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A sweet dessert made with cocoa"},{"prompt":"I enjoy a bowl of popcorn.","options":["🍿 Popcorn","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A snack often eaten at the movies"},{"prompt":"He likes a hot dog at the game.","options":["🌭 Hot Dog","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A sausage in a bun, often topped with mustard"},{"prompt":"She loves a bowl of ice cream.","options":["🍦 Ice Cream","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A cold, sweet dessert made from milk"},{"prompt":"I like to snack on almonds.","options":["🌰 Almonds","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A type of nut that is often roasted"},{"prompt":"They enjoy a fresh salad.","options":["🥗 Salad","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A dish made with mixed vegetables"},{"prompt":"He drinks a smoothie with berries.","options":["🥤 Smoothie","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A blended drink often made with fruit"},{"prompt":"I like a warm bowl of oatmeal.","options":["🥣 Oatmeal","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A breakfast dish made from oats"},{"prompt":"She loves to bake cookies.","options":["🍪 Cookies","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0,"hint":"A sweet baked treat that comes in many flavors"}]}', 8),
('en', 'A1', 'listening', 'School Days', 'Listen to classroom items', '{"type":"listen_and_choose","instructions":"Select the correct object.","exercises":[{"prompt":"I open my book.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":0,"hint":"You read this"},{"prompt":"I write with a pen.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":1,"hint":"Used for writing"},{"prompt":"My backpack is heavy.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":2,"hint":"You carry your things in this"},{"prompt":"I use a ruler in math.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":3,"hint":"Used to measure things"},{"prompt":"The teacher has a pencil.","options":["✏️ Pencil","🖥️ Computer","📓 Notebook","💺 Chair"],"correct":0,"hint":"Used for drawing or writing"},{"prompt":"I need my ruler to draw a straight line.","options":["📏 Ruler","🎒 Backpack","🖊️ Pen","📖 Book"],"correct":0,"hint":"Used for measuring and drawing"},{"prompt":"I put my lunch in the backpack.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":2,"hint":"You carry food and supplies in this"},{"prompt":"I read an interesting story in my book.","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":0,"hint":"Contains pages with text"},{"prompt":"I correct my work with an eraser.","options":["📖 Book","🖊️ Pen","🎒 Backpack","🧹 Eraser"],"correct":3,"hint":"Used to remove pencil marks"},{"prompt":"I draw a picture with my crayons.","options":["🖍️ Crayon","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":0,"hint":"Used for coloring"},{"prompt":"I need my notebook to take notes.","options":["📖 Book","📝 Notebook","🎒 Backpack","📏 Ruler"],"correct":1,"hint":"Contains blank pages for writing"},{"prompt":"I use my tablet to watch videos.","options":["🖊️ Pen","📖 Book","📱 Tablet","🎒 Backpack"],"correct":2,"hint":"A device for browsing the internet"},{"prompt":"I carry my laptop in my backpack.","options":["📖 Book","🎒 Backpack","💻 Laptop","📏 Ruler"],"correct":2,"hint":"Used for working or studying"},{"prompt":"I highlight important text with a marker.","options":["📖 Book","🖊️ Pen","🖍️ Marker","🎒 Backpack"],"correct":2,"hint":"Used for emphasizing text"},{"prompt":"I check my homework with a calculator.","options":["📖 Book","🖊️ Pen","🎒 Backpack","🧮 Calculator"],"correct":3,"hint":"Used for math operations"},{"prompt":"I take my lunch out of the lunchbox.","options":["🎒 Backpack","🍱 Lunchbox","📖 Book","🖊️ Pen"],"correct":1,"hint":"Holds food for meals"},{"prompt":"I use my scissors to cut paper.","options":["📖 Book","🖊️ Pen","✂️ Scissors","🎒 Backpack"],"correct":2,"hint":"Used for cutting"},{"prompt":"I take notes in class with a notebook.","options":["📖 Book","📝 Notebook","🎒 Backpack","🖊️ Pen"],"correct":1,"hint":"Used for writing information"},{"prompt":"I play games on my smartphone.","options":["📖 Book","📱 Smartphone","🎒 Backpack","🖊️ Pen"],"correct":1,"hint":"A mobile device for communication"},{"prompt":"I keep my art supplies in a pencil case.","options":["📖 Book","🎒 Backpack","🖊️ Pen","🖌️ Pencil Case"],"correct":3,"hint":"Used to organize writing tools"}]}', 9);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'listening', 'Fun Weekends', 'Listen to weekend activities', '{"type":"listen_and_choose","instructions":"Choose the activity.","exercises":[{"prompt":"I will go to the beach with my family.","options":["🏖️ Beach","⛰️ Mountains","Camping","Stadium"],"correct":0,"hint":"They are going to the sea"},{"prompt":"I am going to play soccer on Saturday.","options":["⚽ Soccer","🏀 Basketball","🎾 Tennis","🏈 Football"],"correct":0,"hint":"A popular sport with a round ball"},{"prompt":"We are watching a movie at the cinema.","options":["🎬 Cinema","🎭 Theater","🏟️ Stadium","🏫 School"],"correct":0,"hint":"A place for films"},{"prompt":"I like to swim in the pool.","options":["🏊 Swimming","🚴 Cycling","🏃 Running","🚶 Walking"],"correct":0,"hint":"An activity in water"},{"prompt":"They are going to a birthday party.","options":["🎂 Party","🏢 Office","🏥 Hospital","🏦 Bank"],"correct":0,"hint":"A celebration with cake"},{"prompt":"I will visit my grandparents this weekend.","options":["🏠 Home","🏡 Grandparents'' House","🏖️ Beach","🏞️ Park"],"correct":1,"hint":"A place where family members often live"},{"prompt":"She loves to dance at parties.","options":["🎶 Music","💃 Dance","🎤 Sing","🎸 Play Guitar"],"correct":1,"hint":"A fun activity to move to the rhythm"},{"prompt":"They are going hiking in the mountains.","options":["🏖️ Beach","⛰️ Mountains","🌲 Forest","🏕️ Camp"],"correct":1,"hint":"An outdoor activity on high ground"},{"prompt":"I am baking cookies for my friends.","options":["🍪 Baking","🍰 Cooking","🍕 Eating","🥗 Salad"],"correct":0,"hint":"A sweet treat often made for sharing"},{"prompt":"We will go shopping for groceries.","options":["🛒 Shopping","👗 Clothes","🎮 Video Games","📚 Books"],"correct":0,"hint":"Buying food and household items"},{"prompt":"He enjoys swimming in the pool.","options":["🏊 Swimming","🚴 Cycling","🏃 Running","🎾 Tennis"],"correct":0,"hint":"An activity in the water"},{"prompt":"They are having a picnic in the park.","options":["🏕️ Camping","🧺 Picnic","🏖️ Beach","🛶 Canoeing"],"correct":1,"hint":"Eating outdoors on a blanket"},{"prompt":"I will read a book at the library.","options":["📖 Library","🏫 School","🏢 Office","🏠 Home"],"correct":0,"hint":"A place filled with many books"},{"prompt":"She is painting a picture for her art class.","options":["🎨 Painting","🎻 Playing Violin","🎬 Filming","📸 Photography"],"correct":0,"hint":"Creating art with colors"},{"prompt":"We are going to a concert tonight.","options":["🎤 Concert","🎭 Play","🎬 Movie","🏟️ Sports Event"],"correct":0,"hint":"A live music performance"},{"prompt":"I will take my dog for a walk.","options":["🚶 Walking","🏃 Running","🏊 Swimming","🛴 Riding"],"correct":0,"hint":"Leisurely movement on foot"},{"prompt":"They are taking a road trip this summer.","options":["🚗 Road Trip","✈️ Flight","🚢 Cruise","🏖️ Beach Vacation"],"correct":0,"hint":"Traveling by car over a long distance"},{"prompt":"I am learning to play the piano.","options":["🎹 Piano","🎸 Guitar","🎻 Violin","🥁 Drums"],"correct":0,"hint":"A musical instrument with keys"},{"prompt":"We are practicing for the school play.","options":["🎭 Play","🎤 Singing","🎶 Music","🏆 Sports"],"correct":0,"hint":"A theatrical performance"},{"prompt":"She is visiting a museum this afternoon.","options":["🏛️ Museum","🏢 Office","🏫 School","🏞️ Park"],"correct":0,"hint":"A place to see art and history"}]}', 5),
('en', 'A2', 'listening', 'Travel Destinations', 'Identify travel spots', '{"type":"listen_and_choose","instructions":"Pick the correct place.","exercises":[{"prompt":"I want to visit Paris and see the Eiffel Tower.","options":["🗼 Paris","🗽 New York","🏰 London","🕌 Dubai"],"correct":0,"hint":"A famous city in France"},{"prompt":"We are going to New York to see the Statue of Liberty.","options":["🗼 Paris","🗽 New York","🏰 London","🕌 Dubai"],"correct":1,"hint":"A famous city in the USA"},{"prompt":"I would love to see the Big Ben in London.","options":["🗼 Paris","🗽 New York","🏰 London","🕌 Dubai"],"correct":2,"hint":"The capital of the UK"},{"prompt":"The Burj Khalifa is in Dubai.","options":["🗼 Paris","🗽 New York","🏰 London","🕌 Dubai"],"correct":3,"hint":"A city with very tall buildings"},{"prompt":"I am visiting Tokyo next month.","options":["🇯🇵 Tokyo","🇮🇳 Delhi","🇦🇺 Sydney","🇧🇷 Rio"],"correct":0,"hint":"The capital of Japan"},{"prompt":"I want to explore the Colosseum in Rome.","options":["🏰 Rome","🗼 Paris","🕌 Dubai","🗽 New York"],"correct":0,"hint":"The capital city of Italy"},{"prompt":"We are going to visit the Great Wall in China.","options":["🏰 London","🕌 Beijing","🗼 Paris","🗽 New York"],"correct":1,"hint":"A major city in East Asia"},{"prompt":"I want to see the Sagrada Familia in Barcelona.","options":["🏰 Barcelona","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"A famous city in Spain"},{"prompt":"I am excited to visit the Taj Mahal in India.","options":["🏰 Tokyo","🕌 Agra","🗽 New York","🗼 Paris"],"correct":1,"hint":"A city known for its beautiful mausoleum"},{"prompt":"We plan to see the pyramids in Cairo.","options":["🕌 Cairo","🏰 Rome","🗼 Paris","🗽 New York"],"correct":0,"hint":"The capital city of Egypt"},{"prompt":"I can''t wait to visit the Acropolis in Athens.","options":["🏰 Athens","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"The capital city of Greece"},{"prompt":"I am heading to Sydney to see the Opera House.","options":["🗼 Paris","🗽 New York","🏰 Sydney","🕌 Dubai"],"correct":2,"hint":"A major city in Australia"},{"prompt":"I want to visit the Christ the Redeemer statue in Rio.","options":["🏰 Rio de Janeiro","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"A famous city in Brazil"},{"prompt":"We are going to see the Blue Mosque in Istanbul.","options":["🏰 Istanbul","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"A city that straddles Europe and Asia"},{"prompt":"I want to explore the Kremlin in Moscow.","options":["🏰 Moscow","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"The capital city of Russia"},{"prompt":"I would love to visit the Louvre Museum in Paris.","options":["🏰 Paris","🗼 London","🗽 New York","🕌 Dubai"],"correct":0,"hint":"A famous city known for art and culture"},{"prompt":"We are going to see the Colosseum in Rome.","options":["🏰 Rome","🗼 Paris","🗽 New York","🕌 Cairo"],"correct":0,"hint":"An ancient city in Italy"},{"prompt":"I want to visit the Burj Khalifa in Dubai.","options":["🕌 Dubai","🏰 Rome","🗼 Paris","🗽 New York"],"correct":0,"hint":"The tallest building in the world"},{"prompt":"I am excited to see the Niagara Falls in Canada.","options":["🏰 Niagara Falls","🗼 Paris","🗽 New York","🕌 Dubai"],"correct":0,"hint":"A famous natural wonder shared by two countries"}]}', 6),
('en', 'A2', 'listening', 'At the Market', 'Listen to items to buy', '{"type":"listen_and_choose","instructions":"Select the item.","exercises":[{"prompt":"I need to buy a bottle of milk.","options":["🥛 Milk","🍎 Apple","🍞 Bread","🧀 Cheese"],"correct":0,"hint":"A white drink for breakfast"},{"prompt":"Can you get some fresh bread?","options":["🥛 Milk","🍎 Apple","🍞 Bread","🧀 Cheese"],"correct":2,"hint":"Made at a bakery"},{"prompt":"I will buy three red tomatoes.","options":["🍅 Tomato","🧅 Onion","🥔 Potato","🥕 Carrot"],"correct":0,"hint":"Used in salad and soup"},{"prompt":"Do we need any eggs?","options":["🥚 Eggs","🥓 Bacon","🌭 Sausage","🥞 Pancake"],"correct":0,"hint":"Chickens lay these"},{"prompt":"I want to buy some chocolate.","options":["🍫 Chocolate","🍬 Candy","🍦 Ice Cream","🍪 Cookie"],"correct":0,"hint":"A sweet brown treat"},{"prompt":"I want to eat a juicy orange.","options":["🍊 Orange","🍌 Banana","🍏 Apple","🍇 Grape"],"correct":0,"hint":"A citrus fruit, often eaten as a snack"},{"prompt":"Please buy some crispy lettuce.","options":["🥬 Lettuce","🥒 Cucumber","🥕 Carrot","🌽 Corn"],"correct":0,"hint":"Often used in salads"},{"prompt":"I need a pound of chicken.","options":["🍗 Chicken","🐟 Fish","🥩 Beef","🍖 Pork"],"correct":0,"hint":"A common protein source"},{"prompt":"Can you get some sweet strawberries?","options":["🍓 Strawberry","🍏 Apple","🍌 Banana","🍍 Pineapple"],"correct":0,"hint":"Red and often used in desserts"},{"prompt":"I would like some green grapes.","options":["🍇 Grape","🍊 Orange","🍉 Watermelon","🍒 Cherry"],"correct":0,"hint":"Small, round, and often eaten fresh"},{"prompt":"I want two ripe avocados.","options":["🥑 Avocado","🍅 Tomato","🥬 Lettuce","🥒 Cucumber"],"correct":0,"hint":"Often used in guacamole"},{"prompt":"Can I have a cup of hot coffee?","options":["☕ Coffee","🍵 Tea","🥛 Milk","🍫 Chocolate"],"correct":0,"hint":"A popular morning beverage"},{"prompt":"I need some crunchy carrots.","options":["🥕 Carrot","🌽 Corn","🥒 Cucumber","🍆 Eggplant"],"correct":0,"hint":"Often used in salads and snacks"},{"prompt":"Please get a piece of chocolate cake.","options":["🍰 Cake","🍪 Cookie","🍩 Donut","🍦 Ice cream"],"correct":0,"hint":"A sweet dessert often enjoyed at parties"},{"prompt":"I want to buy a loaf of whole grain bread.","options":["🍞 Bread","🥯 Bagel","🥐 Croissant","🥖 Baguette"],"correct":0,"hint":"A staple food made from flour"},{"prompt":"Can you buy some fresh basil?","options":["🌿 Basil","🌶️ Pepper","🍄 Mushroom","🥬 Spinach"],"correct":0,"hint":"An aromatic herb used in cooking"},{"prompt":"I will take a bowl of oatmeal.","options":["🥣 Oatmeal","🍚 Rice","🥔 Potato","🍞 Bread"],"correct":0,"hint":"A warm breakfast cereal"},{"prompt":"I need a bottle of olive oil.","options":["🛢️ Olive oil","🍯 Honey","🐄 Butter","🥛 Milk"],"correct":0,"hint":"Used for cooking and dressing salads"},{"prompt":"Can you get some creamy yogurt?","options":["🍦 Ice cream","🥛 Milk","🍦 Yogurt","🍰 Cake"],"correct":2,"hint":"A dairy product often eaten as a snack"},{"prompt":"I would like some ripe bananas.","options":["🍌 Banana","🍏 Apple","🍊 Orange","🍇 Grape"],"correct":0,"hint":"A yellow fruit that is sweet and soft"}]}', 7),
('en', 'A2', 'listening', 'Party Decorations', 'Identify party elements', '{"type":"listen_and_choose","instructions":"Choose the correct part of the party.","exercises":[{"prompt":"The chocolate cake is delicious.","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"The main sweet food at a party"},{"prompt":"Look at all the colorful balloons!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":2,"hint":"Floating decorations"},{"prompt":"I have a big gift for you.","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":3,"hint":"A present in a box"},{"prompt":"The music is very loud.","options":["🎵 Music","🔦 Light","🍕 Food","🥤 Drink"],"correct":0,"hint":"Something you hear"},{"prompt":"Everyone is wearing party hats.","options":["🥳 Party Hat","👓 Glasses","🧣 Scarf","🧤 Gloves"],"correct":0,"hint":"Used to celebrate"},{"prompt":"Everyone loves to play games at the party.","options":["🎲 Game","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"An activity for fun"},{"prompt":"Let''s pop the confetti poppers!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":1,"hint":"A small explosive party item"},{"prompt":"Don''t forget to wear your party hats!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":1,"hint":"A fun accessory for guests"},{"prompt":"The ice cream is melting!","options":["🍦 Ice Cream","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"A cold, sweet treat"},{"prompt":"We need candles for the birthday cake.","options":["🎂 Cake","🎉 Popper","🕯️ Candle","🎁 Gift"],"correct":2,"hint":"Used for making a wish"},{"prompt":"Look at the cute party decorations!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":2,"hint":"Colorful items that add fun"},{"prompt":"I can''t wait to open my birthday gifts!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":3,"hint":"Wrapped presents"},{"prompt":"We have a music playlist for dancing.","options":["🎶 Music","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"Sounds for enjoyment"},{"prompt":"This party has a great atmosphere!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":1,"hint":"Celebratory sounds"},{"prompt":"Don''t forget to take pictures with the photo booth!","options":["📸 Photo","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"Capturing memories"},{"prompt":"Make sure to invite all your friends!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","👫 Friends"],"correct":3,"hint":"People who celebrate together"},{"prompt":"Let''s make a toast with our drinks!","options":["🥤 Drink","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"What you raise to celebrate"},{"prompt":"The party is starting soon!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","🕒 Time"],"correct":3,"hint":"When the event begins"},{"prompt":"Everyone is here to celebrate!","options":["🎂 Cake","🎉 Popper","🎈 Balloon","👫 Friends"],"correct":3,"hint":"Companions at the party"},{"prompt":"The party invitations were sent out last week.","options":["✉️ Invitation","🎉 Popper","🎈 Balloon","🎁 Gift"],"correct":0,"hint":"What tells people about the event"}]}', 8),
('en', 'A2', 'listening', 'Keeping Healthy', 'Listen to health advice', '{"type":"listen_and_choose","instructions":"Pick the healthy choice.","exercises":[{"prompt":"You should drink eight glasses of water every day.","options":["💧 Water","☕ Coffee","🍔 Burger","🍟 Fries"],"correct":0,"hint":"Essential for life"},{"prompt":"Exercising daily is good for your body.","options":["🏃 Running","📺 TV","🚗 Driving","🎮 Gaming"],"correct":0,"hint":"Being active"},{"prompt":"Eating vegetables makes you strong.","options":["🥦 Broccoli","🍕 Pizza","🍩 Donut","🍫 Chocolate"],"correct":0,"hint":"Healthy green food"},{"prompt":"You need to sleep for eight hours.","options":["😴 Sleep","🎤 Sing","💃 Dance","🏢 Work"],"correct":0,"hint":"Resting at night"},{"prompt":"Remember to wash your hands.","options":["🧼 Soap","📱 Phone","🔑 Key","🖊️ Pen"],"correct":0,"hint":"Important for hygiene"},{"prompt":"Eating fruits helps to boost your immune system.","options":["🍎 Apple","🍔 Burger","🍦 Ice Cream","🍿 Popcorn"],"correct":0,"hint":"Nature''s candy"},{"prompt":"Whole grains are better than refined grains.","options":["🍞 Whole Wheat Bread","🥖 White Bread","🥨 Pretzel","🍩 Donut"],"correct":0,"hint":"Good for digestion"},{"prompt":"Nuts are a great source of healthy fats.","options":["🥜 Almonds","🍟 Fries","🍪 Cookie","🍰 Cake"],"correct":0,"hint":"Crunchy and nutritious"},{"prompt":"Lean proteins help build muscles.","options":["🥩 Chicken Breast","🍕 Pepperoni Pizza","🍔 Cheeseburger","🍟 Chicken Nuggets"],"correct":0,"hint":"A healthy meat choice"},{"prompt":"Dairy products provide calcium for strong bones.","options":["🥛 Milk","🍭 Candy","🥤 Soda","🍦 Ice Cream"],"correct":0,"hint":"Good for kids and adults"},{"prompt":"Fish is a good source of omega-3 fatty acids.","options":["🐟 Salmon","🍗 Fried Chicken","🍖 Ribs","🍕 Cheese Pizza"],"correct":0,"hint":"Heart-healthy option"},{"prompt":"Eating breakfast helps improve concentration.","options":["🥣 Oatmeal","🍩 Donut","🍕 Pizza","🍔 Fast Food"],"correct":0,"hint":"Start the day right"},{"prompt":"Snacking on yogurt can be a healthy choice.","options":["🍦 Yogurt","🍪 Cookie","🍫 Chocolate","🍭 Lollipop"],"correct":0,"hint":"Creamy and good for digestion"},{"prompt":"Green tea is a healthy beverage option.","options":["🍵 Green Tea","☕ Coffee","🍹 Soda","🥤 Energy Drink"],"correct":0,"hint":"Rich in antioxidants"},{"prompt":"A balanced diet includes a variety of food groups.","options":["🍲 Vegetable Soup","🍔 Fast Food","🍫 Chocolate Bar","🍩 Donut"],"correct":0,"hint":"Colorful and nutritious"},{"prompt":"Portion control is important for maintaining a healthy weight.","options":["🍽️ Salad","🍕 Large Pizza","🍔 Double Cheeseburger","🍟 Large Fries"],"correct":0,"hint":"Fill your plate with veggies"},{"prompt":"Dark chocolate can be a healthier dessert option.","options":["🍫 Dark Chocolate","🍦 Ice Cream","🍩 Donut","🍪 Cookie"],"correct":0,"hint":"Rich and indulgent"},{"prompt":"Using olive oil is a healthier alternative for cooking.","options":["🫒 Olive Oil","🧈 Butter","🍔 Margarine","🍟 Frying Oil"],"correct":0,"hint":"Heart-healthy fat"},{"prompt":"Staying hydrated is important for overall health.","options":["💧 Water","🍺 Beer","🥤 Soda","🍹 Cocktail"],"correct":0,"hint":"Essential for every function"},{"prompt":"Eating whole fruits instead of juice is healthier.","options":["🍊 Orange","🥤 Orange Juice","🍭 Candy","🍪 Cookie"],"correct":0,"hint":"Fiber-rich choice"}]}', 9);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'speaking', 'I Like Food', 'Talk about favorite food', '{"type":"speak_and_compare","instructions":"Listen and repeat the sentence clearly.","exercises":[{"prompt":"I love pizza.","expected":"i love pizza","hint":"A round flat bread with toppings"},{"prompt":"I like sweet apples.","expected":"i like sweet apples","hint":"A red or green fruit"},{"prompt":"I eat bread and butter.","expected":"i eat bread and butter","hint":"A common breakfast"},{"prompt":"Ice cream is cold.","expected":"ice cream is cold","hint":"A frozen dessert"},{"prompt":"I drink fresh milk.","expected":"i drink fresh milk","hint":"A white drink from cows"},{"prompt":"I enjoy drinking tea.","expected":"i enjoy drinking tea","hint":"A warm beverage often served in cups"},{"prompt":"I have a pet dog.","expected":"i have a pet dog","hint":"A loyal animal often called man''s best friend"},{"prompt":"I read interesting books.","expected":"i read interesting books","hint":"Written works that tell stories or provide information"},{"prompt":"I play soccer on weekends.","expected":"i play soccer on weekends","hint":"A popular sport played with a round ball"},{"prompt":"I like to watch movies.","expected":"i like to watch movies","hint":"Films that entertain or tell stories"},{"prompt":"I enjoy hiking in nature.","expected":"i enjoy hiking in nature","hint":"Walking in the mountains or forests"},{"prompt":"I drink fresh orange juice.","expected":"i drink fresh orange juice","hint":"A drink made from a citrus fruit"},{"prompt":"I like to swim in the ocean.","expected":"i like to swim in the ocean","hint":"A large body of saltwater"},{"prompt":"I love to cook new recipes.","expected":"i love to cook new recipes","hint":"Instructions for making food"},{"prompt":"I often visit my grandparents.","expected":"i often visit my grandparents","hint":"Parents of your parents"},{"prompt":"I enjoy listening to music.","expected":"i enjoy listening to music","hint":"Art created with sounds"},{"prompt":"I like to travel to new places.","expected":"i like to travel to new places","hint":"Going to different cities or countries"},{"prompt":"I often go for morning walks.","expected":"i often go for morning walks","hint":"A healthy activity done outside"},{"prompt":"I love gardening in my backyard.","expected":"i love gardening in my backyard","hint":"Growing plants and flowers"},{"prompt":"I like to paint in my free time.","expected":"i like to paint in my free time","hint":"Creating art with colors"}]}', 6),
('en', 'A1', 'speaking', 'My Day', 'Describe daily activities', '{"type":"speak_and_compare","instructions":"Speak the daily routine sentences.","exercises":[{"prompt":"I wake up at seven.","expected":"i wake up at seven","hint":"Starting your day"},{"prompt":"I brush my white teeth.","expected":"i brush my white teeth","hint":"Part of morning hygiene"},{"prompt":"I put on my shoes.","expected":"i put on my shoes","hint":"Getting ready to go out"},{"prompt":"I go to school now.","expected":"i go to school now","hint":"Leaving for class"},{"prompt":"I come home at four.","expected":"i come home at four","hint":"Ending your school day"},{"prompt":"I eat breakfast at eight.","expected":"i eat breakfast at eight","hint":"Starting the day with a meal"},{"prompt":"I take a shower.","expected":"i take a shower","hint":"Part of morning routine"},{"prompt":"I read the newspaper.","expected":"i read the newspaper","hint":"Staying informed"},{"prompt":"I go to work by bus.","expected":"i go to work by bus","hint":"Commuting to my job"},{"prompt":"I have lunch at noon.","expected":"i have lunch at noon","hint":"Midday meal"},{"prompt":"I finish work at five.","expected":"i finish work at five","hint":"End of the workday"},{"prompt":"I exercise in the evening.","expected":"i exercise in the evening","hint":"Staying active"},{"prompt":"I prepare dinner.","expected":"i prepare dinner","hint":"Cooking a meal"},{"prompt":"I watch TV after dinner.","expected":"i watch tv after dinner","hint":"Evening relaxation"},{"prompt":"I read a book before bed.","expected":"i read a book before bed","hint":"Winding down at night"},{"prompt":"I brush my hair.","expected":"i brush my hair","hint":"Part of personal grooming"},{"prompt":"I set my alarm for the next day.","expected":"i set my alarm for the next day","hint":"Preparing for tomorrow"},{"prompt":"I go to bed at eleven.","expected":"i go to bed at eleven","hint":"Ending the day"},{"prompt":"I check my emails in the morning.","expected":"i check my emails in the morning","hint":"Starting the day connected"},{"prompt":"I take my dog for a walk.","expected":"i take my dog for a walk","hint":"Daily pet care"}]}', 7),
('en', 'A1', 'speaking', 'The Weather', 'Talk about the weather', '{"type":"speak_and_compare","instructions":"Repeat the weather sentences.","exercises":[{"prompt":"It is a sunny day.","expected":"it is a sunny day","hint":"When the sun is out"},{"prompt":"It is raining today.","expected":"it is raining today","hint":"When the sky is wet"},{"prompt":"The sky is blue.","expected":"the sky is blue","hint":"A clear day"},{"prompt":"It is very cold.","expected":"it is very cold","hint":"When you need a jacket"},{"prompt":"The wind is strong.","expected":"the wind is strong","hint":"When the air moves fast"},{"prompt":"It is very windy outside.","expected":"it is very windy outside","hint":"When the trees are swaying"},{"prompt":"There is a chance of snow tomorrow.","expected":"there is a chance of snow tomorrow","hint":"When it''s cold and white stuff falls"},{"prompt":"The temperature is rising.","expected":"the temperature is rising","hint":"When it feels warmer"},{"prompt":"It is foggy this morning.","expected":"it is foggy this morning","hint":"When you can''t see far"},{"prompt":"The sun is setting.","expected":"the sun is setting","hint":"When day turns to night"},{"prompt":"It is chilly outside.","expected":"it is chilly outside","hint":"When you need a jacket"},{"prompt":"The forecast predicts thunderstorms.","expected":"the forecast predicts thunderstorms","hint":"When you hear thunder"},{"prompt":"It is a cloudy afternoon.","expected":"it is a cloudy afternoon","hint":"When the sun is hidden"},{"prompt":"There are scattered showers today.","expected":"there are scattered showers today","hint":"When it rains on and off"},{"prompt":"It is a beautiful spring day.","expected":"it is a beautiful spring day","hint":"When flowers bloom"},{"prompt":"The humidity is high.","expected":"the humidity is high","hint":"When the air feels sticky"},{"prompt":"It is a perfect day for a picnic.","expected":"it is a perfect day for a picnic","hint":"When the weather is nice"},{"prompt":"The weather is unpredictable.","expected":"the weather is unpredictable","hint":"When it changes often"},{"prompt":"It is a hot summer evening.","expected":"it is a hot summer evening","hint":"When you need to cool down"},{"prompt":"There is a blizzard warning.","expected":"there is a blizzard warning","hint":"When a lot of snow is expected"}]}', 8),
('en', 'A1', 'speaking', 'Introduce Family', 'Talk about family members', '{"type":"speak_and_compare","instructions":"Say the sentences about your family.","exercises":[{"prompt":"This is my brother.","expected":"this is my brother","hint":"A male sibling"},{"prompt":"This is my kind mother.","expected":"this is my kind mother","hint":"A female parent"},{"prompt":"I have a small sister.","expected":"i have a small sister","hint":"A female sibling"},{"prompt":"My father is tall.","expected":"my father is tall","hint":"A male parent"},{"prompt":"I love my family.","expected":"i love my family","hint":"A warm feeling"},{"prompt":"This is my loving father.","expected":"this is my loving father","hint":"A male parent"},{"prompt":"I have an older brother.","expected":"i have an older brother","hint":"A male sibling who is older"},{"prompt":"This is my sweet grandmother.","expected":"this is my sweet grandmother","hint":"A female grandparent"},{"prompt":"I have a younger sister.","expected":"i have a younger sister","hint":"A female sibling who is younger"},{"prompt":"This is my fun uncle.","expected":"this is my fun uncle","hint":"A male relative, brother of a parent"},{"prompt":"This is my caring aunt.","expected":"this is my caring aunt","hint":"A female relative, sister of a parent"},{"prompt":"I have a wonderful cousin.","expected":"i have a wonderful cousin","hint":"A child of my uncle or aunt"},{"prompt":"This is my supportive spouse.","expected":"this is my supportive spouse","hint":"A partner in marriage"},{"prompt":"I have two nephews.","expected":"i have two nephews","hint":"Male children of my sibling"},{"prompt":"This is my lovely niece.","expected":"this is my lovely niece","hint":"Female child of my sibling"},{"prompt":"I have a friendly dog.","expected":"i have a friendly dog","hint":"A pet that is often considered family"},{"prompt":"This is my supportive sister-in-law.","expected":"this is my supportive sister-in-law","hint":"The wife of my brother"},{"prompt":"I have a cheerful father-in-law.","expected":"i have a cheerful father-in-law","hint":"The father of my spouse"},{"prompt":"This is my amazing stepmother.","expected":"this is my amazing stepmother","hint":"The wife of my father who is not my biological mother"},{"prompt":"I have a nice stepbrother.","expected":"i have a nice stepbrother","hint":"The son of my stepparent"}]}', 9),
('en', 'A1', 'speaking', 'Colors Everywhere', 'Name colors in sentences', '{"type":"speak_and_compare","instructions":"Say the color names in sentences.","exercises":[{"prompt":"The bright sky is blue.","expected":"the bright sky is blue","hint":"🔵"},{"prompt":"The fresh grass is green.","expected":"the fresh grass is green","hint":"🟢"},{"prompt":"The big sun is yellow.","expected":"the big sun is yellow","hint":"🟡"},{"prompt":"The sweet apple is red.","expected":"the sweet apple is red","hint":"🔴"},{"prompt":"The small orange is orange.","expected":"the small orange is orange","hint":"🟠"},{"prompt":"The ripe apple is red.","expected":"the ripe apple is red","hint":"🔴"},{"prompt":"The fluffy clouds are white.","expected":"the fluffy clouds are white","hint":"⚪"},{"prompt":"The vibrant flowers are pink.","expected":"the vibrant flowers are pink","hint":"🟣"},{"prompt":"The warm sand is beige.","expected":"the warm sand is beige","hint":"🟡"},{"prompt":"The deep ocean is navy blue.","expected":"the deep ocean is navy blue","hint":"🔵"},{"prompt":"The cheerful sunflowers are yellow.","expected":"the cheerful sunflowers are yellow","hint":"🟡"},{"prompt":"The elegant evening sky is purple.","expected":"the elegant evening sky is purple","hint":"🟣"},{"prompt":"The fresh lemons are bright yellow.","expected":"the fresh lemons are bright yellow","hint":"🟡"},{"prompt":"The shiny car is silver.","expected":"the shiny car is silver","hint":"⚪"},{"prompt":"The juicy watermelon is pink inside.","expected":"the juicy watermelon is pink inside","hint":"🟣"},{"prompt":"The rich chocolate is brown.","expected":"the rich chocolate is brown","hint":"🟤"},{"prompt":"The clear night sky is black.","expected":"the clear night sky is black","hint":"⚫"},{"prompt":"The autumn leaves are orange.","expected":"the autumn leaves are orange","hint":"🟠"},{"prompt":"The bright traffic sign is red.","expected":"the bright traffic sign is red","hint":"🔴"},{"prompt":"The cool ice is light blue.","expected":"the cool ice is light blue","hint":"🔵"}]}', 10);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'speaking', 'My Next Trip', 'Discuss travel plans', '{"type":"speak_and_compare","instructions":"Practice speaking about future travel.","exercises":[{"prompt":"I will visit London next year.","expected":"i will visit london next year","hint":"Planning a trip"},{"prompt":"I want to see the mountains.","expected":"i want to see the mountains","hint":"A high place"},{"prompt":"I will fly by plane.","expected":"i will fly by plane","hint":"Mode of transport"},{"prompt":"I am packing my suitcase.","expected":"i am packing my suitcase","hint":"Getting ready to travel"},{"prompt":"It will be a long flight.","expected":"it will be a long flight","hint":"Spending time in the air"},{"prompt":"I will explore ancient ruins in Greece.","expected":"i will explore ancient ruins in greece","hint":"Historical sites"},{"prompt":"I plan to take a road trip along the coast.","expected":"i plan to take a road trip along the coast","hint":"Travel by car"},{"prompt":"I want to go backpacking in South America.","expected":"i want to go backpacking in south america","hint":"Adventure travel"},{"prompt":"I will visit my friends in Australia.","expected":"i will visit my friends in australia","hint":"Social trip"},{"prompt":"I hope to see the Northern Lights.","expected":"i hope to see the northern lights","hint":"Natural phenomenon"},{"prompt":"I will book a cruise to the Caribbean.","expected":"i will book a cruise to the caribbean","hint":"Sailing vacation"},{"prompt":"I am excited to attend a music festival in Europe.","expected":"i am excited to attend a music festival in europe","hint":"Cultural event"},{"prompt":"I plan to visit national parks this summer.","expected":"i plan to visit national parks this summer","hint":"Nature exploration"},{"prompt":"I will learn to surf in Hawaii.","expected":"i will learn to surf in hawaii","hint":"Water sport"},{"prompt":"I want to try local cuisine in Thailand.","expected":"i want to try local cuisine in thailand","hint":"Food adventure"},{"prompt":"I will take a train through the mountains.","expected":"i will take a train through the mountains","hint":"Scenic travel"},{"prompt":"I plan to volunteer abroad next year.","expected":"i plan to volunteer abroad next year","hint":"Service trip"},{"prompt":"I will attend a wedding in Italy.","expected":"i will attend a wedding in italy","hint":"Special occasion"},{"prompt":"I hope to visit the pyramids in Egypt.","expected":"i hope to visit the pyramids in egypt","hint":"Ancient wonders"},{"prompt":"I want to take a photography tour in Japan.","expected":"i want to take a photography tour in japan","hint":"Hobby trip"}]}', 4),
('en', 'A2', 'speaking', 'Shopping List', 'Practice shopping dialogue', '{"type":"speak_and_compare","instructions":"Say these shopping phrases.","exercises":[{"prompt":"How much is this shirt?","expected":"how much is this shirt","hint":"Asking for the price"},{"prompt":"I would like two red apples.","expected":"i would like two red apples","hint":"Ordering fruit"},{"prompt":"Do you have any fresh milk?","expected":"do you have any fresh milk","hint":"Asking for a product"},{"prompt":"I will pay with my card.","expected":"i will pay with my card","hint":"Payment method"},{"prompt":"Where is the supermarket?","expected":"where is the supermarket","hint":"Asking for location"},{"prompt":"Can I try this jacket on?","expected":"can i try this jacket on","hint":"Requesting to try clothing"},{"prompt":"What time do you close today?","expected":"what time do you close today","hint":"Inquiring about store hours"},{"prompt":"I need a larger size, please.","expected":"i need a larger size please","hint":"Requesting a different size"},{"prompt":"Do you have any discounts available?","expected":"do you have any discounts available","hint":"Asking about sales"},{"prompt":"Where can I find the checkout?","expected":"where can i find the checkout","hint":"Asking for location in the store"},{"prompt":"Could you help me find a gift?","expected":"could you help me find a gift","hint":"Requesting assistance"},{"prompt":"I would like to return this item.","expected":"i would like to return this item","hint":"Initiating a return"},{"prompt":"Is this on sale?","expected":"is this on sale","hint":"Asking about a discount"},{"prompt":"Can you recommend a good book?","expected":"can you recommend a good book","hint":"Seeking advice on products"},{"prompt":"I’m looking for a birthday present.","expected":"im looking for a birthday present","hint":"Stating shopping purpose"},{"prompt":"Do you have this in a different color?","expected":"do you have this in a different color","hint":"Inquiring about options"},{"prompt":"I’ll take this one, please.","expected":"ill take this one please","hint":"Making a purchase decision"},{"prompt":"How long is the warranty?","expected":"how long is the warranty","hint":"Asking about product details"},{"prompt":"Can I pay with a credit card?","expected":"can i pay with a credit card","hint":"Inquiring about payment options"},{"prompt":"Do you have any gluten-free options?","expected":"do you have any gluten free options","hint":"Asking about dietary choices"}]}', 5),
('en', 'A2', 'speaking', 'Healthy Living', 'Give health advice', '{"type":"speak_and_compare","instructions":"Speak these health tips.","exercises":[{"prompt":"Drink more water every day.","expected":"drink more water every day","hint":"Good for hydration"},{"prompt":"Eat fresh fruit and vegetables.","expected":"eat fresh fruit and vegetables","hint":"Proper nutrition"},{"prompt":"Go for a run in the park.","expected":"go for a run in the park","hint":"Physical exercise"},{"prompt":"Get enough sleep every night.","expected":"get enough sleep every night","hint":"Essential for rest"},{"prompt":"Avoid too much sugar.","expected":"avoid too much sugar","hint":"Health warning"},{"prompt":"Get at least 7 hours of sleep each night.","expected":"get at least 7 hours of sleep each night","hint":"Rest is essential for health"},{"prompt":"Practice deep breathing exercises.","expected":"practice deep breathing exercises","hint":"Helps reduce stress"},{"prompt":"Limit sugary snacks and drinks.","expected":"limit sugary snacks and drinks","hint":"Better for your teeth"},{"prompt":"Take regular breaks when working.","expected":"take regular breaks when working","hint":"Improves focus and productivity"},{"prompt":"Incorporate strength training into your routine.","expected":"incorporate strength training into your routine","hint":"Builds muscle and strength"},{"prompt":"Avoid smoking and excessive alcohol consumption.","expected":"avoid smoking and excessive alcohol consumption","hint":"Promotes long-term health"},{"prompt":"Engage in social activities regularly.","expected":"engage in social activities regularly","hint":"Boosts mental health"},{"prompt":"Eat smaller portions at meals.","expected":"eat smaller portions at meals","hint":"Helps with weight management"},{"prompt":"Include whole grains in your diet.","expected":"include whole grains in your diet","hint":"Good for digestion"},{"prompt":"Spend time outdoors in nature.","expected":"spend time outdoors in nature","hint":"Improves mood"},{"prompt":"Practice mindfulness or meditation.","expected":"practice mindfulness or meditation","hint":"Calms the mind"},{"prompt":"Limit screen time before bed.","expected":"limit screen time before bed","hint":"Promotes better sleep"},{"prompt":"Schedule regular health check-ups.","expected":"schedule regular health check-ups","hint":"Proactive health management"},{"prompt":"Learn to cook healthy meals at home.","expected":"learn to cook healthy meals at home","hint":"Control your ingredients"},{"prompt":"Find a hobby that you enjoy.","expected":"find a hobby that you enjoy","hint":"Enhances life satisfaction"},{"prompt":"Stay informed about health topics.","expected":"stay informed about health topics","hint":"Empower yourself"}]}', 6),
('en', 'A2', 'speaking', 'Birthday Party', 'Talk about celebrations', '{"type":"speak_and_compare","instructions":"Speak these party sentences.","exercises":[{"prompt":"Happy birthday to my friend!","expected":"happy birthday to my friend","hint":"A celebration"},{"prompt":"I am bringing a big gift.","expected":"i am bringing a big gift","hint":"A present"},{"prompt":"We will eat chocolate cake.","expected":"we will eat chocolate cake","hint":"A sweet treat"},{"prompt":"The party starts at five.","expected":"the party starts at five","hint":"The time"},{"prompt":"I hope you enjoy your day.","expected":"i hope you enjoy your day","hint":"Well-wishes"},{"prompt":"Let''s dance to the music!","expected":"lets dance to the music","hint":"Movement to rhythm"},{"prompt":"I invited everyone to my party.","expected":"i invited everyone to my party","hint":"A gathering"},{"prompt":"The decorations are so colorful.","expected":"the decorations are so colorful","hint":"Visual appeal"},{"prompt":"We are playing fun games.","expected":"we are playing fun games","hint":"Entertainment"},{"prompt":"I love the party atmosphere!","expected":"i love the party atmosphere","hint":"Vibe of celebration"},{"prompt":"Don''t forget to take photos!","expected":"dont forget to take photos","hint":"Capturing memories"},{"prompt":"Let''s toast to friendship.","expected":"lets toast to friendship","hint":"Celebrating bonds"},{"prompt":"We have a lot of snacks to share.","expected":"we have a lot of snacks to share","hint":"Food for everyone"},{"prompt":"The party starts at seven o''clock.","expected":"the party starts at seven oclock","hint":"Time to celebrate"},{"prompt":"Everyone is wearing party hats.","expected":"everyone is wearing party hats","hint":"Dress for the occasion"},{"prompt":"Let''s make some fun memories tonight.","expected":"lets make some fun memories tonight","hint":"Cherishing moments"},{"prompt":"I brought my favorite drinks.","expected":"i brought my favorite drinks","hint":"Beverages for the event"},{"prompt":"We are having a dance-off!","expected":"we are having a dance off","hint":"Friendly competition"},{"prompt":"Can you help me with the setup?","expected":"can you help me with the setup","hint":"Preparing for the event"},{"prompt":"The music is so lively!","expected":"the music is so lively","hint":"Energetic tunes"}]}', 7),
('en', 'A2', 'speaking', 'Weekend Fun', 'Talk about weekend plans', '{"type":"speak_and_compare","instructions":"Discuss your weekend.","exercises":[{"prompt":"I will go hiking on Saturday.","expected":"i will go hiking on saturday","hint":"Outdoor activity"},{"prompt":"I plan to read a new book.","expected":"i plan to read a new book","hint":"Relaxation"},{"prompt":"We are meeting for coffee.","expected":"we are meeting for coffee","hint":"Social activity"},{"prompt":"I will visit my grandparents.","expected":"i will visit my grandparents","hint":"Family time"},{"prompt":"The weekend was very fun.","expected":"the weekend was very fun","hint":"Summarizing"},{"prompt":"I will watch a movie at home.","expected":"i will watch a movie at home","hint":"Home entertainment"},{"prompt":"We are going to a concert on Saturday night.","expected":"we are going to a concert on saturday night","hint":"Live music"},{"prompt":"I plan to cook a special dinner.","expected":"i plan to cook a special dinner","hint":"Culinary activity"},{"prompt":"I will visit my grandparents.","expected":"i will visit my grandparents","hint":"Family time"},{"prompt":"I am taking a yoga class.","expected":"i am taking a yoga class","hint":"Fitness activity"},{"prompt":"We are having a picnic in the park.","expected":"we are having a picnic in the park","hint":"Outdoor meal"},{"prompt":"I will attend a workshop on photography.","expected":"i will attend a workshop on photography","hint":"Learning new skills"},{"prompt":"I plan to go shopping for groceries.","expected":"i plan to go shopping for groceries","hint":"Errand"},{"prompt":"We are going to the beach for the day.","expected":"we are going to the beach for the day","hint":"Water activity"},{"prompt":"I will spend time with my friends.","expected":"i will spend time with my friends","hint":"Socializing"},{"prompt":"I plan to garden in the afternoon.","expected":"i plan to garden in the afternoon","hint":"Outdoor hobby"},{"prompt":"We are going for a bike ride.","expected":"we are going for a bike ride","hint":"Exercise"},{"prompt":"I will play video games all weekend.","expected":"i will play video games all weekend","hint":"Indoor entertainment"},{"prompt":"I am volunteering at the local shelter.","expected":"i am volunteering at the local shelter","hint":"Community service"},{"prompt":"We are planning a road trip.","expected":"we are planning a road trip","hint":"Travel"}]}', 8);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'reading', 'Name the Animals', 'Read and match animals', '{"type":"read_and_choose","instructions":"Read the word and pick the matching icon.","exercises":[{"question":"Cat","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Dog","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":1},{"question":"Rabbit","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":2},{"question":"Bird","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3},{"question":"Hamster","options":["🐹 Hamster","🐘 Elephant","🦁 Lion","🦒 Giraffe"],"correct":0},{"question":"Bird","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":3},{"question":"Fish","options":["🐟 Fish","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Horse","options":["🐴 Horse","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Frog","options":["🐸 Frog","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Turtle","options":["🐢 Turtle","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Lion","options":["🦁 Lion","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Elephant","options":["🐘 Elephant","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Monkey","options":["🐒 Monkey","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Penguin","options":["🐧 Penguin","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Mouse","options":["🐭 Mouse","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Pig","options":["🐷 Pig","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Sheep","options":["🐑 Sheep","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Chicken","options":["🐔 Chicken","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Goat","options":["🐐 Goat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0},{"question":"Bear","options":["🐻 Bear","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0}]}', 6),
('en', 'A1', 'reading', 'Color Reading', 'Read color words', '{"type":"read_and_choose","instructions":"Match the word to the color circle.","exercises":[{"question":"Red","options":["🔴 Red","🔵 Blue","🟢 Green","🟡 Yellow"],"correct":0},{"question":"Blue","options":["🔴 Red","🔵 Blue","🟢 Green","🟡 Yellow"],"correct":1},{"question":"Green","options":["🔴 Red","🔵 Blue","🟢 Green","🟡 Yellow"],"correct":2},{"question":"Yellow","options":["🔴 Red","🔵 Blue","🟢 Green","🟡 Yellow"],"correct":3},{"question":"Orange","options":["🟠 Orange","🟣 Purple","⚫ Black","⚪ White"],"correct":0},{"question":"Yellow","options":["🟡 Yellow","🔴 Red","🔵 Blue","🟢 Green"],"correct":0},{"question":"Purple","options":["🟣 Purple","🔴 Red","🔵 Blue","🟢 Green"],"correct":0},{"question":"Orange","options":["🟠 Orange","🔴 Red","🟡 Yellow","🔵 Blue"],"correct":0},{"question":"Cyan","options":["🟡 Yellow","🟢 Green","🔵 Blue","🟣 Cyan"],"correct":3},{"question":"Pink","options":["🔴 Red","🟣 Purple","🟡 Yellow","🌸 Pink"],"correct":3},{"question":"Olive","options":["🟢 Green","🟣 Purple","🟡 Yellow","🫒 Olive"],"correct":3},{"question":"Teal","options":["🟢 Green","🔵 Blue","🟣 Purple","🟣 Teal"],"correct":3},{"question":"Brown","options":["🟤 Brown","🔴 Red","🟡 Yellow","🟢 Green"],"correct":0},{"question":"Magenta","options":["🟣 Purple","🔴 Red","🟡 Yellow","🟣 Magenta"],"correct":3},{"question":"Lavender","options":["🟣 Lavender","🔴 Red","🟢 Green","🟡 Yellow"],"correct":0},{"question":"Navy","options":["🔵 Navy","🟡 Yellow","🔴 Red","🟢 Green"],"correct":0},{"question":"Coral","options":["🟠 Coral","🔴 Red","🟡 Yellow","🔵 Blue"],"correct":0},{"question":"Gold","options":["🟡 Gold","🔴 Red","🔵 Blue","🟢 Green"],"correct":0},{"question":"Indigo","options":["🔵 Blue","🟣 Indigo","🟢 Green","🔴 Red"],"correct":1},{"question":"Mint","options":["🟢 Mint","🟡 Yellow","🔵 Blue","🔴 Red"],"correct":0}]}', 7),
('en', 'A1', 'reading', 'Short Stories 1', 'Read short story fragments', '{"type":"read_and_choose","instructions":"Answer the question about the text.","passage":"Tom has a big red ball. He plays in the park with his friend Sam.","exercises":[{"question":"What does Tom have?","options":["A ball","A cat","A book","A pen"],"correct":0},{"question":"Where does Tom play?","options":["Park","School","Home","Mall"],"correct":0},{"question":"Who is with Tom?","options":["Sam","Mom","Dad","Teacher"],"correct":0},{"question":"What color is the ball?","options":["Red","Blue","Green","Yellow"],"correct":0},{"question":"Is the ball small?","options":["No, it is big","Yes","I don''t know","Maybe"],"correct":0},{"question":"What color is Tom''s ball?","options":["Red","Blue","Green","Yellow"],"correct":1},{"question":"What does Tom like to eat?","options":["Pizza","Salad","Ice cream","Rice"],"correct":2},{"question":"What does Tom wear?","options":["Shorts","Pajamas","A dress","A suit"],"correct":0},{"question":"What is Tom''s favorite game?","options":["Soccer","Chess","Hide and Seek","Tennis"],"correct":2},{"question":"What does Tom do after school?","options":["Play video games","Do homework","Watch TV","Go to bed"],"correct":1},{"question":"What pet does Tom want?","options":["Dog","Fish","Bird","Rabbit"],"correct":0},{"question":"What is Tom''s favorite subject?","options":["Math","Science","History","Art"],"correct":3},{"question":"What does Tom''s mom do?","options":["Teacher","Doctor","Engineer","Artist"],"correct":0},{"question":"Where does Tom''s family go on vacation?","options":["Beach","Mountains","City","Countryside"],"correct":0},{"question":"What time does Tom wake up?","options":["7 AM","6 AM","8 AM","9 AM"],"correct":0},{"question":"What instrument does Tom play?","options":["Piano","Guitar","Drums","Violin"],"correct":1},{"question":"What does Tom collect?","options":["Stamps","Coins","Toys","Cards"],"correct":0},{"question":"Who helps Tom with his homework?","options":["Sister","Friend","Teacher","Dad"],"correct":3},{"question":"What sport does Tom play?","options":["Basketball","Baseball","Football","Hockey"],"correct":0},{"question":"What does Tom do on weekends?","options":["Go hiking","Visit grandparents","Stay home","Go shopping"],"correct":1}]}', 8),
('en', 'A1', 'reading', 'Food Words', 'Read health food items', '{"type":"read_and_choose","instructions":"Match the food word to its icon.","exercises":[{"question":"Apple","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":0},{"question":"Banana","options":["🍎 Apple","🍌 Banana","🍇 Grapes","🍊 Orange"],"correct":1},{"question":"Bread","options":["🍞 Bread","🥖 Baguette","🥐 Croissant","🍰 Cake"],"correct":0},{"question":"Milk","options":["🥛 Milk","🥤 Juice","☕ Coffee","🍷 Wine"],"correct":0},{"question":"Chocolate","options":["🍫 Chocolate","🍬 Candy","🍦 Ice Cream","🍪 Cookie"],"correct":0},{"question":"Carrot","options":["🥕 Carrot","🌽 Corn","🥔 Potato","🍆 Eggplant"],"correct":0},{"question":"Rice","options":["🍚 Rice","🍜 Noodles","🍝 Pasta","🍱 Bento"],"correct":0},{"question":"Cheese","options":["🧀 Cheese","🍖 Meat","🥩 Steak","🍗 Chicken"],"correct":0},{"question":"Fish","options":["🐟 Fish","🍗 Chicken","🥩 Steak","🍤 Shrimp"],"correct":0},{"question":"Strawberry","options":["🍓 Strawberry","🍈 Melon","🍉 Watermelon","🍏 Green Apple"],"correct":0},{"question":"Cookie","options":["🍪 Cookie","🍰 Cake","🍩 Donut","🍫 Chocolate"],"correct":0},{"question":"Grapefruit","options":["🍊 Orange","🍈 Melon","🍋 Lemon","🍊 Grapefruit"],"correct":3},{"question":"Pineapple","options":["🍍 Pineapple","🍏 Green Apple","🍊 Orange","🍌 Banana"],"correct":0},{"question":"Onion","options":["🧅 Onion","🥒 Cucumber","🌶️ Pepper","🥕 Carrot"],"correct":0},{"question":"Olive","options":["🫒 Olive","🍒 Cherry","🥭 Mango","🍏 Green Apple"],"correct":0},{"question":"Pasta","options":["🍝 Pasta","🍜 Noodles","🍚 Rice","🍕 Pizza"],"correct":0},{"question":"Ice Cream","options":["🍦 Ice Cream","🍧 Shaved Ice","🍨 Sundae","🍰 Cake"],"correct":0},{"question":"Nut","options":["🥜 Nut","🌰 Chestnut","🍏 Green Apple","🍊 Orange"],"correct":0},{"question":"Peach","options":["🍑 Peach","🍍 Pineapple","🍏 Green Apple","🍓 Strawberry"],"correct":0},{"question":"Tomato","options":["🍅 Tomato","🥒 Cucumber","🥕 Carrot","🌽 Corn"],"correct":0}]}', 9),
('en', 'A1', 'reading', 'Class Objects', 'Identify school items', '{"type":"read_and_choose","instructions":"Match the object word to its icon.","exercises":[{"question":"Book","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":0},{"question":"Pen","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":1},{"question":"Ruler","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":3},{"question":"Backpack","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":2},{"question":"Pencil","options":["✏️ Pencil","🖥️ Computer","📓 Notebook","💺 Chair"],"correct":0},{"question":"Backpack","options":["📖 Book","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":2},{"question":"Scissors","options":["✂️ Scissors","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0},{"question":"Notebook","options":["📝 Notebook","🖊️ Pen","🎒 Backpack","📏 Ruler"],"correct":0},{"question":"Pencil","options":["🖊️ Pen","✏️ Pencil","🎒 Backpack","📏 Ruler"],"correct":1},{"question":"Eraser","options":["📏 Ruler","✏️ Pencil","🖊️ Pen","🧽 Eraser"],"correct":3},{"question":"Glue","options":["📖 Book","🖊️ Pen","🧴 Glue","📏 Ruler"],"correct":2},{"question":"Folder","options":["📁 Folder","📖 Book","🎒 Backpack","📏 Ruler"],"correct":0},{"question":"Highlighter","options":["🖊️ Pen","🎨 Highlighter","📖 Book","📏 Ruler"],"correct":1},{"question":"Calculator","options":["🖊️ Pen","📖 Book","🧮 Calculator","📏 Ruler"],"correct":2},{"question":"Paper","options":["📄 Paper","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0},{"question":"Sharpener","options":["📏 Ruler","✏️ Pencil","🖊️ Pen","🌀 Sharpener"],"correct":3},{"question":"Chart","options":["📊 Chart","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0},{"question":"Marker","options":["🖍️ Marker","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0},{"question":"Stapler","options":["📎 Stapler","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0},{"question":"Tape","options":["📦 Tape","📖 Book","🖊️ Pen","📏 Ruler"],"correct":0}]}', 10);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'reading', 'Travel Story', 'Read a travel narrative', '{"type":"read_and_choose","instructions":"Answer questions about Anna''s trip.","passage":"Anna flew to Paris last summer. She visited the Eiffel Tower and ate many delicious croissants. The weather was sunny every day.","exercises":[{"question":"Where did Anna go?","options":["London","Paris","Rome","Berlin"],"correct":1},{"question":"When did she go?","options":["Last summer","Last winter","Last week","Yesterday"],"correct":0},{"question":"What did she see?","options":["Statue of Liberty","Eiffel Tower","Big Ben","Colosseum"],"correct":1},{"question":"What did she eat?","options":["Pizza","croissants","Salad","Pasta"],"correct":1},{"question":"What was the weather like?","options":["Rainy","Sunny","Cloudy","Snowy"],"correct":1},{"question":"How did Anna travel?","options":["By train","By car","By airplane","By bus"],"correct":2},{"question":"Who did she travel with?","options":["Her family","Her friends","Her colleagues","By herself"],"correct":1},{"question":"What was the weather like?","options":["Rainy","Sunny","Snowy","Windy"],"correct":1},{"question":"What food did Anna try?","options":["Pizza","Sushi","Croissant","Tacos"],"correct":2},{"question":"What was her favorite activity?","options":["Shopping","Sightseeing","Dining out","Hiking"],"correct":1},{"question":"How long did she stay?","options":["One day","One week","Two weeks","One month"],"correct":1},{"question":"What language did she practice?","options":["Spanish","French","Italian","German"],"correct":1},{"question":"What souvenir did she buy?","options":["A keychain","A magnet","A painting","A scarf"],"correct":0},{"question":"What hotel did she stay in?","options":["A luxury hotel","A hostel","An Airbnb","A bed and breakfast"],"correct":0},{"question":"What cultural event did she attend?","options":["A concert","A festival","An art exhibition","A theater play"],"correct":1},{"question":"What mode of transportation did she use locally?","options":["Bicycle","Subway","Taxi","Walking"],"correct":1},{"question":"What museum did she visit?","options":["The Louvre","The British Museum","The Vatican Museums","The Uffizi Gallery"],"correct":0},{"question":"What landmark did she take a photo of?","options":["The Arc de Triomphe","The Colosseum","The Sagrada Familia","The Brandenburg Gate"],"correct":0},{"question":"What was the highlight of her trip?","options":["Meeting new people","Exploring new places","Trying new foods","Learning a new language"],"correct":1},{"question":"What did she miss the most while traveling?","options":["Her home","Her pets","Her friends","Her favorite foods"],"correct":0}]}', 4),
('en', 'A2', 'reading', 'Shopping Day', 'Read a shopping conversation', '{"type":"read_and_choose","instructions":"Answer questions about the shopping trip.","passage":"Mike went to the supermarket. He bought five red apples and a bottle of fresh milk. He paid with his bank card and went home to cook.","exercises":[{"question":"What did Mike buy first?","options":["Bread","Apples","Cheese","Milk"],"correct":1},{"question":"How many apples?","options":["Three","Four","Five","Six"],"correct":2},{"question":"What color were the apples?","options":["Green","Yellow","Red","Orange"],"correct":2},{"question":"How did he pay?","options":["Cash","Bank card","Phone","He didn''t pay"],"correct":1},{"question":"What did he do at home?","options":["Sleep","Watch TV","Cook","Read"],"correct":2},{"question":"What did Mike forget to buy?","options":["Butter","Eggs","Flour","Sugar"],"correct":0},{"question":"How many types of cheese did Mike buy?","options":["One","Two","Three","Four"],"correct":1},{"question":"What type of bread did Mike choose?","options":["Sourdough","Whole grain","White","Rye"],"correct":1},{"question":"Where did Mike go shopping?","options":["Supermarket","Local market","Online","Convenience store"],"correct":0},{"question":"What did Mike buy for breakfast?","options":["Cereal","Toast","Pancakes","Bagels"],"correct":1},{"question":"What fruit did Mike buy besides apples?","options":["Bananas","Oranges","Grapes","Pears"],"correct":0},{"question":"How much did Mike spend in total?","options":["$20","$30","$40","$50"],"correct":1},{"question":"What did Mike plan to make with the cheese?","options":["Sandwich","Salad","Pasta","Pizza"],"correct":3},{"question":"What kind of milk did Mike choose?","options":["Almond","Soy","Whole","Skim"],"correct":2},{"question":"What snack did Mike buy?","options":["Chips","Cookies","Nuts","Granola bars"],"correct":1},{"question":"Did Mike buy any vegetables?","options":["Yes","No"],"correct":0},{"question":"What did Mike use to carry his groceries?","options":["Backpack","Shopping cart","Tote bag","Plastic bags"],"correct":1},{"question":"What dessert did Mike buy?","options":["Ice cream","Cake","Brownies","Pudding"],"correct":0},{"question":"How did Mike pay for his groceries?","options":["Cash","Credit card","Debit card","Gift card"],"correct":1},{"question":"What did Mike say he would make for dinner?","options":["Tacos","Stir fry","Soup","Grilled cheese"],"correct":3}]}', 5),
('en', 'A2', 'reading', 'A Birthday Note', 'Read a birthday message', '{"type":"read_and_choose","instructions":"Comprehend the birthday note.","passage":"Dear Sam, Happy Birthday! I hope you have a wonderful day. I have a surprise gift for you. See you at the party at 5 PM! Love, Anna.","exercises":[{"question":"Who is the note for?","options":["Sam","Tom","Anna","Mike"],"correct":0},{"question":"Who wrote the note?","options":["Sam","Anna","Teacher","Mom"],"correct":1},{"question":"What does Anna have for Sam?","options":["A book","A surprise gift","A card","Nothing"],"correct":1},{"question":"What time is the party?","options":["3 PM","4 PM","5 PM","6 PM"],"correct":2},{"question":"What is the event?","options":["A school day","A birthday","A trip","A movie"],"correct":1},{"question":"What day is Sam''s birthday?","options":["March 5th","April 10th","January 1st","February 20th"],"correct":1},{"question":"What does Anna wish for Sam?","options":["Happiness","Success","Adventure","All the best"],"correct":3},{"question":"Where will the party be held?","options":["At the park","At Anna''s house","At school","At a restaurant"],"correct":1},{"question":"What is Sam turning this year?","options":["10 years old","11 years old","12 years old","13 years old"],"correct":2},{"question":"What activity is planned for the party?","options":["Baking","Outdoor games","Movie watching","Crafting"],"correct":1},{"question":"What color is the birthday cake?","options":["Blue","Pink","Chocolate","Yellow"],"correct":0},{"question":"How many friends are invited?","options":["Five","Ten","Twelve","Twenty"],"correct":2},{"question":"What kind of gift does Anna plan to give?","options":["A toy","A video game","A book","A puzzle"],"correct":2},{"question":"What does Anna hope Sam will enjoy?","options":["The cake","The decorations","The gifts","The games"],"correct":3},{"question":"What special message does Anna write in the note?","options":["You''re the best!","Happy Birthday!","Have fun!","Enjoy your day!"],"correct":1},{"question":"What flavor is Sam''s favorite cake?","options":["Vanilla","Chocolate","Strawberry","Lemon"],"correct":1},{"question":"What type of party does Anna want to have?","options":["Surprise party","Theme party","Outdoor party","Sleepover party"],"correct":0},{"question":"What time is the party?","options":["2 PM","3 PM","4 PM","5 PM"],"correct":1},{"question":"What does Anna plan to decorate with?","options":["Balloons","Flowers","Streamers","All of the above"],"correct":3},{"question":"What does Anna remind everyone to bring?","options":["A gift","A friend","A snack","A card"],"correct":0}]}', 6),
('en', 'A2', 'reading', 'Health Guide', 'Read health advice', '{"type":"read_and_choose","instructions":"Determine if the health tip is correct.","exercises":[{"question":"Drink eight glasses of water daily.","options":["True","False"],"correct":0},{"question":"It is good to sleep only 2 hours.","options":["True","False"],"correct":1},{"question":"Vegetables make you healthy.","options":["True","False"],"correct":0},{"question":"Chocolate is better than fruit.","options":["True","False"],"correct":1},{"question":"Executive exercise is important.","options":["True","False"],"correct":0},{"question":"Eating breakfast is important for a healthy start to the day.","options":["True","False"],"correct":0},{"question":"Too much sugar can lead to health issues.","options":["True","False"],"correct":0},{"question":"Regular exercise can improve mental health.","options":["True","False"],"correct":0},{"question":"All fats are bad for your health.","options":["True","False"],"correct":1},{"question":"Eating late at night leads to weight gain.","options":["True","False"],"correct":1},{"question":"You should take vitamins only if you are sick.","options":["True","False"],"correct":1},{"question":"Stress management is essential for overall health.","options":["True","False"],"correct":0},{"question":"Walking is a good form of exercise.","options":["True","False"],"correct":0},{"question":"It''s okay to skip meals to lose weight.","options":["True","False"],"correct":1},{"question":"Consuming whole grains is beneficial for health.","options":["True","False"],"correct":0},{"question":"Too much screen time can affect sleep quality.","options":["True","False"],"correct":0},{"question":"You can drink any type of juice to stay hydrated.","options":["True","False"],"correct":1},{"question":"Lifting weights can help build muscle mass.","options":["True","False"],"correct":0},{"question":"Mental health is just as important as physical health.","options":["True","False"],"correct":0},{"question":"Eating too much protein is harmful to your health.","options":["True","False"],"correct":1}]}', 7),
('en', 'A2', 'reading', 'Weekend Life', 'Read about weekend activities', '{"type":"read_and_choose","instructions":"Finalize the weekend plans.","exercises":[{"question":"Go hiking in the mountains.","options":["Yes","No"],"correct":0},{"question":"Working in the office all day.","options":["Yes","No"],"correct":1},{"question":"Reading a book on the sofa.","options":["Yes","No"],"correct":0},{"question":"Running a marathon.","options":["Yes","No"],"correct":1},{"question":"Eating dinner with family.","options":["Yes","No"],"correct":0},{"question":"Going to the beach for a picnic.","options":["Yes","No"],"correct":0},{"question":"Cleaning the house all Saturday.","options":["Yes","No"],"correct":1},{"question":"Watching a movie at home.","options":["Yes","No"],"correct":0},{"question":"Visiting friends for dinner.","options":["Yes","No"],"correct":0},{"question":"Doing laundry all weekend.","options":["Yes","No"],"correct":1},{"question":"Going out for brunch on Sunday.","options":["Yes","No"],"correct":0},{"question":"Spending the day in bed.","options":["Yes","No"],"correct":0},{"question":"Running errands all day Saturday.","options":["Yes","No"],"correct":1},{"question":"Baking cookies in the kitchen.","options":["Yes","No"],"correct":0},{"question":"Going to a concert on Saturday night.","options":["Yes","No"],"correct":0},{"question":"Playing video games all weekend.","options":["Yes","No"],"correct":1},{"question":"Taking a day trip to the countryside.","options":["Yes","No"],"correct":0},{"question":"Studying for an exam all weekend.","options":["Yes","No"],"correct":1},{"question":"Exploring a new city.","options":["Yes","No"],"correct":0},{"question":"Going to the gym both days.","options":["Yes","No"],"correct":1}]}', 8);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'writing', 'Spell the Colors', 'Type color names correctly', '{"type":"type_word","instructions":"Type the name of the color you see.","exercises":[{"prompt":"🔴","expected":"Red","hint":"The color of fire"},{"prompt":"🔵","expected":"Blue","hint":"The color of the sky"},{"prompt":"🟢","expected":"Green","hint":"The color of grass"},{"prompt":"🟡","expected":"Yellow","hint":"The color of the sun"},{"prompt":"🟠","expected":"Orange","hint":"A fruit has this name too"},{"prompt":"🟡","expected":"Yellow","hint":"The color of the sun"},{"prompt":"🟠","expected":"Orange","hint":"The color of a pumpkin"},{"prompt":"🟣","expected":"Purple","hint":"The color of grapes"},{"prompt":"⚫","expected":"Black","hint":"The color of coal"},{"prompt":"⚪","expected":"White","hint":"The color of snow"},{"prompt":"🟤","expected":"Brown","hint":"The color of chocolate"},{"prompt":"🌈","expected":"Rainbow","hint":"A spectrum of colors in the sky"},{"prompt":"🟩","expected":"Lime","hint":"A bright shade of green"},{"prompt":"🟦","expected":"Cyan","hint":"A light blue color"},{"prompt":"🟧","expected":"Coral","hint":"A pinkish-orange color"},{"prompt":"🟨","expected":"Gold","hint":"The color of precious metal"},{"prompt":"🟪","expected":"Lavender","hint":"A light purple color"},{"prompt":"🌵","expected":"Sage","hint":"A muted green color"},{"prompt":"🌊","expected":"Teal","hint":"A blue-green color"},{"prompt":"🪨","expected":"Slate","hint":"A grayish-blue color"}]}', 6),
('en', 'A1', 'writing', 'Animal Names', 'Type animal names correctly', '{"type":"type_word","instructions":"Type the animal name for the icon.","exercises":[{"prompt":"🐱","expected":"Cat","hint":"Meow"},{"prompt":"🐶","expected":"Dog","hint":"Woof"},{"prompt":"🐦","expected":"Bird","hint":"Tweet"},{"prompt":"🐟","expected":"Fish","hint":"Blub"},{"prompt":"🐘","expected":"Elephant","hint":"A very big animal"},{"prompt":"🐴","expected":"Horse","hint":"Neigh"},{"prompt":"🐘","expected":"Elephant","hint":"Trumpet"},{"prompt":"🐍","expected":"Snake","hint":"Hiss"},{"prompt":"🐒","expected":"Monkey","hint":"Chatter"},{"prompt":"🐻","expected":"Bear","hint":"Growl"},{"prompt":"🐼","expected":"Panda","hint":"Bamboo lover"},{"prompt":"🐧","expected":"Penguin","hint":"Waddle"},{"prompt":"🦁","expected":"Lion","hint":"Roar"},{"prompt":"🦒","expected":"Giraffe","hint":"Tallest land animal"},{"prompt":"🐨","expected":"Koala","hint":"Eucalyptus eater"},{"prompt":"🐙","expected":"Octopus","hint":"Eight arms"},{"prompt":"🦊","expected":"Fox","hint":"Cunning"},{"prompt":"🐠","expected":"Fish","hint":"Swim"},{"prompt":"🐕‍🦺","expected":"Service Dog","hint":"Helper animal"},{"prompt":"🐇","expected":"Rabbit","hint":"Hops"}]}', 7),
('en', 'A1', 'writing', 'Copy Short Sentences', 'Practice writing full sentences', '{"type":"copy_sentence","instructions":"Copy the sentence exactly as shown.","exercises":[{"sentence":"I have a small ball.","expected":"I have a small ball.","hint":"Copy carefully"},{"sentence":"The cat is very happy.","expected":"The cat is very happy.","hint":"Copy carefully"},{"sentence":"I like to eat pizza.","expected":"I like to eat pizza.","hint":"Copy carefully"},{"sentence":"She has a big dog.","expected":"She has a big dog.","hint":"Copy carefully"},{"sentence":"We go to school now.","expected":"We go to school now.","hint":"Copy carefully"},{"sentence":"The sun is shining bright.","expected":"The sun is shining bright.","hint":"Copy carefully"},{"sentence":"She loves to read books.","expected":"She loves to read books.","hint":"Copy carefully"},{"sentence":"They are playing in the park.","expected":"They are playing in the park.","hint":"Copy carefully"},{"sentence":"He runs very fast.","expected":"He runs very fast.","hint":"Copy carefully"},{"sentence":"We enjoy watching movies.","expected":"We enjoy watching movies.","hint":"Copy carefully"},{"sentence":"The flowers are blooming beautifully.","expected":"The flowers are blooming beautifully.","hint":"Copy carefully"},{"sentence":"I want to learn a new language.","expected":"I want to learn a new language.","hint":"Copy carefully"},{"sentence":"The dog barks at strangers.","expected":"The dog barks at strangers.","hint":"Copy carefully"},{"sentence":"It''s time to go to bed.","expected":"It''s time to go to bed.","hint":"Copy carefully"},{"sentence":"She is cooking dinner tonight.","expected":"She is cooking dinner tonight.","hint":"Copy carefully"},{"sentence":"We visited the museum yesterday.","expected":"We visited the museum yesterday.","hint":"Copy carefully"},{"sentence":"He plays the guitar very well.","expected":"He plays the guitar very well.","hint":"Copy carefully"},{"sentence":"The children are laughing happily.","expected":"The children are laughing happily.","hint":"Copy carefully"},{"sentence":"I found a dollar on the ground.","expected":"I found a dollar on the ground.","hint":"Copy carefully"},{"sentence":"She paints beautiful landscapes.","expected":"She paints beautiful landscapes.","hint":"Copy carefully"}]}', 8),
('en', 'A1', 'writing', 'Fill the Gaps', 'Complete simple sentences', '{"type":"fill_blank","instructions":"Choose the correct word to fill the gap.","exercises":[{"sentence":"I ___ a new cat.","options":["have","has","had","having"],"correct":0},{"sentence":"She ___ very happy.","options":["is","are","am","be"],"correct":0},{"sentence":"They ___ to the park.","options":["go","goes","going","gone"],"correct":0},{"sentence":"The sky ___ blue today.","options":["is","are","am","be"],"correct":0},{"sentence":"We ___ breakfast now.","options":["eat","eats","eating","ate"],"correct":0},{"sentence":"We ___ to the movies tonight.","options":["go","goes","going","gone"],"correct":0},{"sentence":"He ___ a great job.","options":["do","does","doing","done"],"correct":1},{"sentence":"I ___ my homework yesterday.","options":["finish","finishes","finished","finishing"],"correct":2},{"sentence":"You ___ like this movie.","options":["will","would","might","can"],"correct":0},{"sentence":"They ___ playing soccer now.","options":["is","are","am","be"],"correct":1},{"sentence":"She ___ to travel every summer.","options":["love","loves","loving","loved"],"correct":1},{"sentence":"The dog ___ barking loudly.","options":["is","are","am","be"],"correct":0},{"sentence":"We ___ a picnic last weekend.","options":["have","has","had","having"],"correct":2},{"sentence":"I ___ my friends after school.","options":["meet","meets","meeting","met"],"correct":0},{"sentence":"He ___ to finish his project.","options":["need","needs","needing","needed"],"correct":1},{"sentence":"They ___ happy with the results.","options":["is","are","am","be"],"correct":1},{"sentence":"You ___ to drink more water.","options":["want","wants","wanting","wanted"],"correct":0},{"sentence":"She ___ her keys every morning.","options":["lose","loses","losing","lost"],"correct":1},{"sentence":"We ___ about the concert next week.","options":["talk","talks","talking","talked"],"correct":0},{"sentence":"I ___ breakfast at 8 AM.","options":["eat","eats","eating","ate"],"correct":0}]}', 9),
('en', 'A1', 'writing', 'Type the Numbers', 'Practice spelling numbers', '{"type":"type_word","instructions":"Type the word for the number.","exercises":[{"prompt":"1","expected":"One","hint":"Starting number"},{"prompt":"2","expected":"Two","hint":"After one"},{"prompt":"3","expected":"Three","hint":"After two"},{"prompt":"4","expected":"Four","hint":"After three"},{"prompt":"5","expected":"Five","hint":"After four"},{"prompt":"4","expected":"Four","hint":"After three"},{"prompt":"5","expected":"Five","hint":"After four"},{"prompt":"6","expected":"Six","hint":"After five"},{"prompt":"7","expected":"Seven","hint":"After six"},{"prompt":"8","expected":"Eight","hint":"After seven"},{"prompt":"9","expected":"Nine","hint":"After eight"},{"prompt":"10","expected":"Ten","hint":"The first double-digit number"},{"prompt":"11","expected":"Eleven","hint":"After ten"},{"prompt":"12","expected":"Twelve","hint":"After eleven"},{"prompt":"13","expected":"Thirteen","hint":"After twelve"},{"prompt":"14","expected":"Fourteen","hint":"After thirteen"},{"prompt":"15","expected":"Fifteen","hint":"After fourteen"},{"prompt":"16","expected":"Sixteen","hint":"After fifteen"},{"prompt":"17","expected":"Seventeen","hint":"After sixteen"},{"prompt":"18","expected":"Eighteen","hint":"After seventeen"}]}', 10);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A2', 'writing', 'Travel Diary', 'Write about a holiday trip', '{"type":"guided_writing","instructions":"Answer the questions about your trip.","exercises":[{"question":"Where did you go?","starter":"I went to ","example":"I went to Paris.","hint":"Name a city"},{"question":"What did you see?","starter":"I saw ","example":"I saw the Eiffel Tower.","hint":"Mention a landmark"},{"question":"What did you eat?","starter":"I ate ","example":"I ate croissants and fruit.","hint":"Mention some food"},{"question":"How was the weather?","starter":"The weather was ","example":"The weather was sunny and hot.","hint":"Describe the sky"},{"question":"Did you like it?","starter":"I liked it because ","example":"I liked it because it was beautiful.","hint":"Give a reason"},{"question":"How did you get there?","starter":"I traveled by ","example":"I traveled by train.","hint":"Mention a mode of transportation"},{"question":"Who did you go with?","starter":"I went with ","example":"I went with my friends.","hint":"Mention a person or group"},{"question":"What activities did you do?","starter":"I did ","example":"I did some hiking.","hint":"Mention an activity"},{"question":"What was the weather like?","starter":"The weather was ","example":"The weather was sunny.","hint":"Describe the weather"},{"question":"What souvenirs did you buy?","starter":"I bought ","example":"I bought a postcard.","hint":"Mention a souvenir"},{"question":"What was your favorite part of the trip?","starter":"My favorite part was ","example":"My favorite part was visiting the museum.","hint":"Describe a memorable experience"},{"question":"How long did you stay?","starter":"I stayed for ","example":"I stayed for a week.","hint":"Mention a duration"},{"question":"What local traditions did you experience?","starter":"I experienced ","example":"I experienced a traditional festival.","hint":"Mention a tradition"},{"question":"What did you learn during your trip?","starter":"I learned ","example":"I learned about the local culture.","hint":"Mention something educational"},{"question":"What was the best place you visited?","starter":"The best place I visited was ","example":"The best place I visited was a beautiful beach.","hint":"Describe a location"},{"question":"What type of accommodation did you stay in?","starter":"I stayed in a ","example":"I stayed in a hotel.","hint":"Mention a type of lodging"},{"question":"What was the most challenging part of your trip?","starter":"The most challenging part was ","example":"The most challenging part was getting lost.","hint":"Describe a challenge"},{"question":"Did you meet any new people?","starter":"I met ","example":"I met some locals.","hint":"Mention someone you met"},{"question":"What transportation did you use within the city?","starter":"I used ","example":"I used the subway.","hint":"Mention a city transport"},{"question":"What is one thing you''d recommend to others?","starter":"I would recommend ","example":"I would recommend trying the local food.","hint":"Mention a recommendation"}]}', 4),
('en', 'A2', 'writing', 'Hobby Description', 'Write about things you enjoy', '{"type":"guided_writing","instructions":"Describe your favorite hobby.","exercises":[{"question":"What is your favorite hobby?","starter":"My favorite hobby is ","example":"My favorite hobby is painting.","hint":"Name the activity"},{"question":"When do you do it?","starter":"I do it on ","example":"I do it on weekends.","hint":"Mention a time"},{"question":"Who do you do it with?","starter":"I do it with ","example":"I do it with my friends.","hint":"Mention people"},{"question":"Why do you like it?","starter":"I like it because ","example":"I like it because it is fun.","hint":"Give a reason"},{"question":"Where do you do it?","starter":"I do it in ","example":"I do it in the park.","hint":"Mention a place"},{"question":"Why do you enjoy this hobby?","starter":"I enjoy this hobby because ","example":"I enjoy this hobby because it relaxes me.","hint":"Explain your feelings"},{"question":"What do you need for this hobby?","starter":"I need ","example":"I need a guitar.","hint":"List materials or equipment"},{"question":"How did you start this hobby?","starter":"I started this hobby when ","example":"I started this hobby when I was a child.","hint":"Talk about beginnings"},{"question":"What skills have you gained from this hobby?","starter":"I have gained skills such as ","example":"I have gained skills such as creativity and patience.","hint":"Mention skills or benefits"},{"question":"What is your favorite memory related to this hobby?","starter":"My favorite memory is when ","example":"My favorite memory is when I performed on stage.","hint":"Share a specific moment"},{"question":"How often do you practice this hobby?","starter":"I practice this hobby ","example":"I practice this hobby every day.","hint":"Mention frequency"},{"question":"What challenges do you face in this hobby?","starter":"I face challenges such as ","example":"I face challenges such as finding time.","hint":"Discuss difficulties"},{"question":"What are your goals related to this hobby?","starter":"My goals are to ","example":"My goals are to improve my skills.","hint":"Talk about future aspirations"},{"question":"Where do you usually do this hobby?","starter":"I usually do this hobby at ","example":"I usually do this hobby at home.","hint":"Specify a location"},{"question":"What do you enjoy most about this hobby?","starter":"What I enjoy most is ","example":"What I enjoy most is the sense of accomplishment.","hint":"Share what brings joy"},{"question":"How has this hobby influenced your life?","starter":"This hobby has influenced my life by ","example":"This hobby has influenced my life by teaching me discipline.","hint":"Discuss impact"},{"question":"What other hobbies do you have?","starter":"I also have other hobbies like ","example":"I also have other hobbies like gardening.","hint":"List additional interests"},{"question":"What inspires you in this hobby?","starter":"I am inspired by ","example":"I am inspired by famous artists.","hint":"Mention sources of inspiration"},{"question":"What is a common misconception about your hobby?","starter":"A common misconception is that ","example":"A common misconception is that it''s too easy.","hint":"Clarify misunderstandings"},{"question":"What advice would you give to a beginner in this hobby?","starter":"I would advise beginners to ","example":"I would advise beginners to practice regularly.","hint":"Offer guidance"}]}', 5),
('en', 'A2', 'writing', 'Write a Letter', 'Practice formal writing basics', '{"type":"guided_writing","instructions":"Finish the short letter.","exercises":[{"question":"How do you start a letter?","starter":"Dear ","example":"Dear Sam,","hint":"Add a name"},{"question":"What is the first question?","starter":"How are ","example":"How are you today?","hint":"Ask how they are"},{"question":"Mention a plan?","starter":"I want to ","example":"I want to visit you.","hint":"State an intention"},{"question":"Ask for a reply?","starter":"Please ","example":"Please write back soon.","hint":"A polite request"},{"question":"How do you end a letter?","starter":"Love, ","example":"Love, Anna.","hint":"Closing and name"},{"question":"How do you express gratitude?","starter":"Thank you for ","example":"Thank you for your help.","hint":"Mention something they did"},{"question":"Ask about their family?","starter":"How is your ","example":"How is your family doing?","hint":"Inquire about their loved ones"},{"question":"Share a recent experience?","starter":"I recently ","example":"I recently went hiking.","hint":"Talk about something you did"},{"question":"Mention a favorite hobby?","starter":"I enjoy ","example":"I enjoy painting.","hint":"Share something you like"},{"question":"Ask for a suggestion?","starter":"Do you have any ","example":"Do you have any book recommendations?","hint":"Seek advice or suggestions"},{"question":"Share a funny story?","starter":"One funny thing that happened is ","example":"One funny thing that happened is I tripped in the park.","hint":"Tell about a humorous event"},{"question":"Invite them to an event?","starter":"I would love for you to ","example":"I would love for you to join my party.","hint":"Extend an invitation"},{"question":"Express your feelings?","starter":"I feel ","example":"I feel happy to hear from you.","hint":"Share your emotions"},{"question":"Mention a shared memory?","starter":"I remember when we ","example":"I remember when we went to the beach.","hint":"Recall a past experience together"},{"question":"Ask about their job?","starter":"How is your job at ","example":"How is your job at the new company?","hint":"Inquire about their work"},{"question":"Share a goal?","starter":"I hope to ","example":"I hope to travel this summer.","hint":"Discuss a personal aspiration"},{"question":"Express excitement?","starter":"I am so excited about ","example":"I am so excited about our upcoming trip.","hint":"Show enthusiasm for something"},{"question":"Mention a recent purchase?","starter":"I just bought a ","example":"I just bought a new laptop.","hint":"Talk about something new you have"},{"question":"Ask about their weekend plans?","starter":"What are your plans for ","example":"What are your plans for the weekend?","hint":"Inquire about their free time"},{"question":"Close the letter warmly?","starter":"Looking forward to hearing from you,","example":"Looking forward to hearing from you, take care!","hint":"End with a friendly note"}]}', 6),
('en', 'A2', 'writing', 'Food Review', 'Write about a meal', '{"type":"guided_writing","instructions":"Describe your favorite food.","exercises":[{"question":"What is your favorite food?","starter":"My favorite food is ","example":"My favorite food is sushi.","hint":"Name the dish"},{"question":"What is in it?","starter":"It has ","example":"It has fish and rice.","hint":"List ingredients"},{"question":"When do you eat it?","starter":"I eat it for ","example":"I eat it for dinner.","hint":"Mention a mealtime"},{"question":"Why?","starter":"Because ","example":"Because it is very tasty.","hint":"Give a reason"},{"question":"Where can you buy it?","starter":"I buy it at ","example":"I buy it at the restaurant.","hint":"Mention a place"},{"question":"What do you like about it?","starter":"I like it because ","example":"I like it because it''s delicious and healthy.","hint":"Share your feelings or opinions"},{"question":"How is it prepared?","starter":"It is prepared by ","example":"It is prepared by grilling or frying.","hint":"Describe the cooking method"},{"question":"Where did you first try it?","starter":"I first tried it at ","example":"I first tried it at a local restaurant.","hint":"Mention a place"},{"question":"What is your favorite way to eat it?","starter":"My favorite way to eat it is ","example":"My favorite way to eat it is with extra sauce.","hint":"Describe a personal preference"},{"question":"Who do you usually eat it with?","starter":"I usually eat it with ","example":"I usually eat it with my family.","hint":"Mention people"},{"question":"What drink pairs well with it?","starter":"A good drink to have with it is ","example":"A good drink to have with it is green tea.","hint":"Suggest a beverage"},{"question":"What is a common side dish?","starter":"A common side dish is ","example":"A common side dish is salad.","hint":"List a side item"},{"question":"Is it a popular dish in your culture?","starter":"Yes, it is popular because ","example":"Yes, it is popular because many people enjoy it.","hint":"Discuss its popularity"},{"question":"Can you make it yourself?","starter":"Yes, I can make it myself by ","example":"Yes, I can make it myself by following a recipe.","hint":"Talk about your cooking skills"},{"question":"What flavor does it have?","starter":"It has a ","example":"It has a sweet and savory flavor.","hint":"Describe the taste"},{"question":"What occasion do you eat it for?","starter":"I eat it for occasions like ","example":"I eat it for occasions like birthdays.","hint":"Mention a special event"},{"question":"How often do you eat it?","starter":"I eat it ","example":"I eat it once a week.","hint":"Talk about frequency"},{"question":"What does it look like?","starter":"It looks like ","example":"It looks like a colorful plate of food.","hint":"Describe its appearance"},{"question":"What is the origin of the dish?","starter":"The dish originated from ","example":"The dish originated from Italy.","hint":"Mention its background"},{"question":"What is your favorite restaurant for it?","starter":"My favorite restaurant for it is ","example":"My favorite restaurant for it is Joe''s Diner.","hint":"Name a restaurant"}]}', 7),
('en', 'A2', 'writing', 'Plans for Future', 'Write about what you will do', '{"type":"guided_writing","instructions":"Write about your future intentions.","exercises":[{"question":"What will you do next summer?","starter":"I will ","example":"I will travel to Spain.","hint":"Mention an action"},{"question":"Where will you go?","starter":"I will go to ","example":"I will go to the beach.","hint":"Mention a place"},{"question":"What will you buy?","starter":"I will buy ","example":"I will buy a new bike.","hint":"Mention an item"},{"question":"Who will be with you?","starter":"I will be with ","example":"I will be with my cousins.","hint":"Mention people"},{"question":"How do you feel?","starter":"I feel ","example":"I feel very excited.","hint":"Describe an emotion"},{"question":"What will you learn this year?","starter":"I will learn ","example":"I will learn to play the guitar.","hint":"Mention a skill or subject"},{"question":"When will you start exercising?","starter":"I will start exercising ","example":"I will start exercising next month.","hint":"Mention a time frame"},{"question":"Who will you meet?","starter":"I will meet ","example":"I will meet my best friend.","hint":"Mention a person"},{"question":"What will you eat for dinner?","starter":"I will eat ","example":"I will eat pasta for dinner.","hint":"Mention a food"},{"question":"What hobby will you pick up?","starter":"I will pick up ","example":"I will pick up painting.","hint":"Mention a hobby"},{"question":"What will you do for your birthday?","starter":"I will celebrate my birthday by ","example":"I will celebrate my birthday by having a party.","hint":"Mention a celebration activity"},{"question":"Where will you study?","starter":"I will study at ","example":"I will study at the university.","hint":"Mention a location"},{"question":"What will you do on the weekend?","starter":"I will ","example":"I will go hiking on the weekend.","hint":"Mention an activity"},{"question":"What will you create?","starter":"I will create ","example":"I will create a blog.","hint":"Mention a project or item"},{"question":"What will you do to help others?","starter":"I will help others by ","example":"I will help others by volunteering.","hint":"Mention a way to assist"},{"question":"What will you watch?","starter":"I will watch ","example":"I will watch a new movie.","hint":"Mention a type of media"},{"question":"What will you do for your health?","starter":"I will improve my health by ","example":"I will improve my health by eating healthier.","hint":"Mention a health-related action"},{"question":"Where will you travel next?","starter":"I will travel to ","example":"I will travel to Italy.","hint":"Mention a destination"},{"question":"What will you do to relax?","starter":"I will relax by ","example":"I will relax by reading a book.","hint":"Mention a relaxation method"},{"question":"What will you do with your family?","starter":"I will spend time with my family by ","example":"I will spend time with my family by having a picnic.","hint":"Mention a family activity"}]}', 8);
